  traceback.print_exc()


COMPA = -1.1E-17#@u_s * 1.0@u_s
COMPB = -2.0E-9#@u_s

V = 5.0@u_V
Freq = 60.@u_MHz

def func1(V, a, b, f):
  Vcorrected = V *(a*f*f + b*f + 1.)
  return Vcorrected

try:
  vout = func1(V,COMPA,COMPB,Freq)
  print(vout)
except:
  traceback.print_exc()

def func2(V, a, b, f):
  print(f)
  if isinstance(f, Unit.UnitValue):
    f = f.value * f._prefixed_unit.power.scale 
  return V *(a*f*f + b*f + 1.)


try:
  vout = func2(V,COMPA,COMPB,Freq)
  print(V,"in becomes",vout, "out.")
except:
  traceback.print_exc()
```

