```
username_error_messages = api_settings.USERNAME_ERROR_MESSAGES
password_error_messages = api_settings.PASSWORD_ERROR_MESSAGES


class JSONWebTokenSerializer(Serializer):
    """
    Serializer class used to validate a username and password.

    'username' is identified by the custom UserModel.USERNAME_FIELD.

    Returns a JSON Web Token that can be used to authenticate later calls.
    """
    def __init__(self, *args, **kwargs):
        """
        Dynamically add the USERNAME_FIELD to self.fields.
        """
        super(JSONWebTokenSerializer, self).__init__(*args, **kwargs)

        if username_error_messages:
            self.fields[self.username_field] = serializers.CharField(
                error_messages=username_error_messages
            )
        else:
            self.fields[self.username_field] = serializers.CharField()

        if password_error_messages:
            self.fields['password'] = PasswordField(
                write_only=True, error_messages=password_error_messages
            )
        else:
            self.fields['password'] = PasswordField(write_only=True)
```

import rdflib

dataGraph = rdflib.Graph()

print "SINGLE QUERY"
query = """SELECT  ?this  WHERE {  
	VALUES ?this { <http://ex.com/a> "HI" }
	FILTER ( ! isBlank(?this) ) 
}"""
result = dataGraph.query(query)
for row in result : print row
assert len(result) > 0

print "NO FILTER"
query = """
SELECT  ?this
WHERE { 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a>  "HI"  }
	  } } 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a> "HI" }
	  } } 
}"""
result = dataGraph.query(query)
for row in result : print row
assert len(result) > 0

print "FILTER in first subquery"
query = """
SELECT  ?this
WHERE { 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a>  "HI"  }
		FILTER ( isIRI(?this) )
	  } } 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a> "HI" }
	  } } 
}"""
result = dataGraph.query(query)
for row in result : print row
assert len(result) > 0

print "FILTER in second subquery"
query = """
SELECT  ?this
WHERE { 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a> "HI" }
	  } } 
	{ SELECT ?this WHERE {  
		VALUES ?this { <http://ex.com/a>  "HI"  }
		FILTER ( isIRI(?this) )
	  } } 
}"""
result = dataGraph.query(query)
